+                      isError: true
+                    })
+                  });
+                }
+            "#;
+            let (_temp_dir, _manager, js_runtime, def) = setup_js_tool(source, "error_tool").await;
+
+            let wrapper = ExtensionToolWrapper::new(def, js_runtime);
+            let output = wrapper
+                .execute("call-1", json!({}), None)
+                .await
+                .expect("execute tool");
