+            assert!(output.is_error);
+            match output.content.as_slice() {
+                [ContentBlock::Text(text)] => {
+                    assert_eq!(text.text, "something went wrong");
+                }
+                other => panic!("expected text content, got {other:?}"),
+            }
+        });
+    }
